public class StringMethodsDemo {
    public static void main(String[] args) {
        String str = "  Hello Java Programming  ";

        System.out.println("=== Basic Methods ===");
        System.out.println("Original: '" + str + "'");
        System.out.println("Length: " + str.length());
        System.out.println("Char at 2: " + str.charAt(2));
        System.out.println("Is empty: " + str.isEmpty());

        System.out.println("\n=== Comparison Methods ===");
        System.out.println("Equals 'Hello': " + str.trim().equals("Hello Java Programming"));
        System.out.println("Compare: " + str.trim().compareTo("Hello Java Programming"));
        System.out.println("Contains 'Java': " + str.contains("Java"));

        System.out.println("\n=== Modification Methods ===");
        System.out.println("Trimmed: '" + str.trim() + "'");
        System.out.println("Upper: " + str.toUpperCase());
        System.out.println("Lower: " + str.toLowerCase());
        System.out.println("Substring (6, 10): '" + str.substring(6, 10) + "'");
        System.out.println("Replace 'Java' with 'Python': " + str.replace("Java", "Python"));

        System.out.println("\n=== Search Methods ===");
        String text = "Java is fun. Java is powerful.";
        System.out.println("Index of 'Java': " + text.indexOf("Java"));
        System.out.println("Last index of 'Java': " + text.lastIndexOf("Java"));
        System.out.println("Starts with 'Java': " + text.startsWith("Java"));
        System.out.println("Ends with '.': " + text.endsWith("."));

        System.out.println("\n=== String Splitting ===");
        String[] words = text.split(" ");
        System.out.println("Split by space:");
        for (String word : words) {
            System.out.println("  '" + word + "'");
        }

        System.out.println("\n=== Join Example ===");
        String joined = String.join("-", "Java", "is", "great");
        System.out.println("Joined: " + joined);

        System.out.println("\n=== String Conversion ===");
        int num = 123;
        String numStr = String.valueOf(num);
        System.out.println("String.valueOf(123): '" + numStr + "'");
        System.out.println("Object to String: " + new Object());
    }
}

public class StringBufferDemo {
    public static void main(String[] args) {
        // StringBuffer
        System.out.println("=== StringBuffer ===");
        StringBuffer sb = new StringBuffer("Hello");
        System.out.println("Original: " + sb);
        System.out.println("Length: " + sb.length());
        System.out.println("Capacity: " + sb.capacity());

        // append
        sb.append(" World");
        System.out.println("After append: " + sb);

        // insert
        sb.insert(5, " Java");
        System.out.println("After insert: " + sb);

        // delete
        sb.delete(5, 10);
        System.out.println("After delete: " + sb);

        // replace
        sb.replace(6, 11, "Universe");
        System.out.println("After replace: " + sb);

        // reverse
        sb.reverse();
        System.out.println("After reverse: " + sb);

        // StringBuilder (similar but not synchronized)
        System.out.println("\n=== StringBuilder ===");
        StringBuilder builder = new StringBuilder("Java");
        System.out.println("Original: " + builder);

        // Chain operations
        builder.append(" is").append(" great").append("!").reverse();
        System.out.println("After chained operations: " + builder);

        // Performance comparison
        System.out.println("\n=== Performance Comparison ===");
        long start = System.currentTimeMillis();

        // String (immutable) - slow
        String str = "";
        for (int i = 0; i < 10000; i++) {
            str += "a";
        }
        long stringTime = System.currentTimeMillis() - start;

        // StringBuilder - fast
        start = System.currentTimeMillis();
        StringBuilder sbuilder = new StringBuilder();
        for (int i = 0; i < 10000; i++) {
            sbuilder.append("a");
        }
        long builderTime = System.currentTimeMillis() - start;

        System.out.println("String (immutable) time: " + stringTime + "ms");
        System.out.println("StringBuilder time: " + builderTime + "ms");

        // StringBuffer and StringBuilder are better than String for modifications
        System.out.println("\n=== Advanced Operations ===");
        StringBuilder sb2 = new StringBuilder("Hello World");
        sb2.deleteCharAt(5);
        System.out.println("After deleteCharAt(5): " + sb2);

        sb2.setCharAt(0, 'h');
        System.out.println("After setCharAt(0, 'h'): " + sb2);

        sb2.setLength(5);
        System.out.println("After setLength(5): " + sb2);
    }
}

public class MathDemo {
    public static void main(String[] args) {
        System.out.println("=== Math Class Demonstration ===\n");

        // Constants
        System.out.println("PI: " + Math.PI);
        System.out.println("E: " + Math.E);

        // Basic operations
        System.out.println("\n=== Basic Operations ===");
        System.out.println("abs(-10): " + Math.abs(-10));
        System.out.println("round(3.7): " + Math.round(3.7));
        System.out.println("round(3.2): " + Math.round(3.2));
        System.out.println("ceil(3.2): " + Math.ceil(3.2));
        System.out.println("floor(3.7): " + Math.floor(3.7));

        // Min and Max
        System.out.println("\n=== Min/Max ===");
        System.out.println("max(10, 20): " + Math.max(10, 20));
        System.out.println("min(10, 20): " + Math.min(10, 20));

        // Power and Root
        System.out.println("\n=== Power and Root ===");
        System.out.println("pow(2, 5): " + Math.pow(2, 5));
        System.out.println("sqrt(25): " + Math.sqrt(25));
        System.out.println("cbrt(27): " + Math.cbrt(27));
        System.out.println("pow(5, 3): " + Math.pow(5, 3));

        // Trigonometry
        System.out.println("\n=== Trigonometry ===");
        double angle = Math.toRadians(45);
        System.out.println("sin(45°): " + Math.sin(angle));
        System.out.println("cos(45°): " + Math.cos(angle));
        System.out.println("tan(45°): " + Math.tan(angle));
        System.out.println("toDegrees(1.0): " + Math.toDegrees(1.0));

        // Logarithmic
        System.out.println("\n=== Logarithmic ===");
        System.out.println("log(2.71828): " + Math.log(Math.E));
        System.out.println("log10(100): " + Math.log10(100));

        // Random numbers
        System.out.println("\n=== Random Numbers ===");
        System.out.println("Random: " + Math.random());
        System.out.println("Random (0-10): " + (int)(Math.random() * 11));
        System.out.println("Random (1-100): " + (int)(Math.random() * 100 + 1));

        // Exponential
        System.out.println("\n=== Exponential ===");
        System.out.println("exp(1): " + Math.exp(1));
        System.out.println("expm1(1): " + Math.expm1(1));

        // Hypotenuse
        System.out.println("\n=== Hypotenuse ===");
        System.out.println("hypot(3, 4): " + Math.hypot(3, 4));

        // Sign
        System.out.println("\n=== Sign ===");
        System.out.println("signum(-5): " + Math.signum(-5));
        System.out.println("signum(0): " + Math.signum(0));
        System.out.println("signum(5): " + Math.signum(5));
    }
}

